            let left_set = match &self.left {
                Some(l) => l.view(),
                None => Set::empty(),
            };
            let right_set = match &self.right {
                Some(r) => r.view(),
                None => Set::empty(),
            };
            left_set.union(right_set).insert(self.val)
        }

