            (match &self.left {
                Some(l) => (forall |x| #[trigger] l.view().contains(x) ==> x < self.val) && l.is_bst(),
                None => true,
            }) && (match &self.right {
                Some(r) => (forall |x| #[trigger] r.view().contains(x) ==> x > self.val) && r.is_bst(),
                None => true,
            })
        }
